}

// MARK: - Network Service

class NetworkService: NSObject, NetworkServiceProtocol, URLSessionDelegate {
    
    static let shared = NetworkService()
    
    private var session: URLSession!
    
    private override init() {
        super.init()
        
        let configuration = URLSessionConfiguration.default
        configuration.timeoutIntervalForRequest = 30
        configuration.timeoutIntervalForResource = 60
        configuration.waitsForConnectivity = true
        
        // Create session with delegate for handling SSL challenges
        session = URLSession(configuration: configuration, delegate: self, delegateQueue: nil)
    }
    
    // MARK: - URLSessionDelegate for SSL handling
    
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        
        guard let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        let host = challenge.protectionSpace.host
        
        // For legacy internal systems, accept the certificate
        // In production, you should pin certificates or use proper CA-signed certs
        if host.hasSuffix("legacy.internal") {
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
            return
        }
        
        // For production API, perform default handling (validates against system trust store)
        completionHandler(.performDefaultHandling, nil)
    }
    
