// MARK: - Token Manager

class TokenManager {
    static let shared = TokenManager()
    
    var accessToken: String? {
        get { UserDefaults.standard.string(forKey: "accessToken") }
        set { UserDefaults.standard.set(newValue, forKey: "accessToken") }
    }
    
    var legacyAPIKey: String? {
        get { UserDefaults.standard.string(forKey: "legacyAPIKey") }
        set { UserDefaults.standard.set(newValue, forKey: "legacyAPIKey") }
    }
    
    private init() {}
}

// MARK: - API Manager

class APIManager {
    static let shared = APIManager()
    private let networkService = NetworkService.shared
    
    private init() {}
    
    // MARK: - Production API Calls
    
    func fetchUsers() async throws -> [User] {
        let response: APIResponse<[User]> = try await networkService.fetchData(
            from: "/v1/users",
            environment: .production,
            responseType: APIResponse<[User]>.self
        )
        guard let users = response.data else {
            throw NetworkError.noData
        }
        return users
    }
    
    func fetchUser(id: Int) async throws -> User {
        let response: APIResponse<User> = try await networkService.fetchData(
            from: "/v1/users/\(id)",
            environment: .production,
            responseType: APIResponse<User>.self
        )
        guard let user = response.data else {
            throw NetworkError.noData
        }
        return user
    }
    
    func createUser(name: String, email: String) async throws -> User {
        struct CreateUserRequest: Codable {
            let name: String
            let email: String
        }
        
        let body = CreateUserRequest(name: name, email: email)
        let response: APIResponse<User> = try await networkService.postData(
            to: "/v1/users",
            environment: .production,
            body: body,
            responseType: APIResponse<User>.self
        )
        guard let user = response.data else {
            throw NetworkError.noData
        }
        return user
    }
    
    // MARK: - Legacy System Calls
    
    func fetchLegacyRecords() async throws -> [LegacyRecord] {
        return try await networkService.fetchData(
            from: "/api/records",
            environment: .legacy,
            responseType: [LegacyRecord].self
        )
    }
    
    func fetchLegacyRecord(id: String) async throws -> LegacyRecord {
        return try await networkService.fetchData(
            from: "/api/records/\(id)",
            environment: .legacy,
            responseType: LegacyRecord.self
        )
    }
    
    func syncRecordToLegacy(record: LegacyRecord) async throws -> LegacyRecord {
        return try await networkService.postData(
            to: "/api/records/sync",
            environment: .legacy,
            body: record,
            responseType: LegacyRecord.self
        )
    }
}

// MARK: - View Model

@MainActor
class MainViewModel: ObservableObject {
    @Published var users: [User] = []
    @Published var legacyRecords: [LegacyRecord] = []
    @Published var isLoadingUsers = false
    @Published var isLoadingRecords = false
    @Published var errorMessage: String?
    @Published var showError = false
    
    private let apiManager = APIManager.shared
    
    func loadUsers() {
        isLoadingUsers = true
        errorMessage = nil
        
        Task {
            do {
                users = try await apiManager.fetchUsers()
                isLoadingUsers = false
            } catch {
                isLoadingUsers = false
                errorMessage = error.localizedDescription
                showError = true
            }
        }
    }
    
    func loadLegacyRecords() {
        isLoadingRecords = true
        errorMessage = nil
        
        Task {
            do {
                legacyRecords = try await apiManager.fetchLegacyRecords()
                isLoadingRecords = false
            } catch {
                isLoadingRecords = false
                errorMessage = error.localizedDescription
                showError = true
            }
        }
    }
    
    func createUser(name: String, email: String) {
        Task {
            do {
                let newUser = try await apiManager.createUser(name: name, email: email)
                users.append(newUser)
            } catch {
                errorMessage = error.localizedDescription
                showError = true
            }
        }
    }
}

